      <div style="display:flex; align-items:center; gap:7px; background:var(--surface); border:1.5px solid var(--surface-border); border-radius:999px; padding:5px 12px;"><svg width="17" height="17" viewBox="0 0 17 17"><circle cx="8.5" cy="8.5" r="7" fill="var(--gold)" stroke="var(--surface-border)" stroke-width="1.6"></circle><path d="M 5.7 11.5 L 10.9 6.1" stroke="#3d2c0e" stroke-width="1.5" stroke-linecap="round" fill="none"></path><path d="M 5.3 7.5 Q 8.5 4.1 11.9 7.9" stroke="#3d2c0e" stroke-width="1.5" stroke-linecap="round" fill="none"></path></svg><span style="font-size:12px; font-weight:700; color:var(--text-muted);">Mining / gold</span></div>
