    <div style="background:var(--surface); border:var(--border-w) solid var(--surface-border); border-radius:var(--radius-m); padding:16px 22px; box-shadow:0 3px 0 var(--shadow-drop); display:flex; align-items:center; gap:14px; flex-wrap:wrap;">
      <span style="font-size:13.5px; color:var(--text-muted);">Written contract for implementers — token schema, naming, component rules, motion &amp; a11y requirements:</span>
      <span style="font-family:var(--font-mono); font-size:13px; background:var(--surface-sunken); border:1.5px solid var(--surface-border); padding:3px 10px; border-radius:8px; color:var(--text);">STYLE.md</span>
    </div>
